    50→/* 
    51→  ═══════════════════════════════════════════════════════════════════════════
    52→  K3RN.LABS CANONICAL DESIGN SYSTEM — CSS VARIABLES
    53→  ═══════════════════════════════════════════════════════════════════════
    54→  
    55→  Source of Truth: k3rn.labs_ui_design_system_canonical.md
    56→  Status: Contractual — Non-negotiable
    57→  
    58→  This file defines the COMPLETE token system for K3RN.LABS.
    59→  Aligned with "Modern Rounded" aesthetic (Radius 24px).
    60→*/
    61→
    62→:root {
    63→  /* ═══════════════════════════════════════════════════════════════════════
    64→     RADIUS TOKENS — "Modern Rounded" (Official Canonical)
    65→     ═══════════════════════════════════════════════════════════════════════ */
    66→  --radius: 0.5rem;
    67→  /* Base reference */
    68→  --radius-sm: 0.375rem;
    69→  /* 6px */
    70→  --radius-md: 0.5rem;
    71→  /* 8px */
    72→  --radius-lg: 0.75rem;
    73→  /* 12px */
    74→  --radius-xl: 1rem;
    75→  /* 16px */
    76→  --radius-2xl: 1.5rem;
    77→  /* 24px - STANDARD CARD RADIUS */
    78→  --radius-full: 9999px;
    79→
    80→  /* ═══════════════════════════════════════════════════════════════════════
    81→     CANONICAL COLOR TOKENS — Backgrounds
    82→     ═══════════════════════════════════════════════════════════════════════ */
    83→  --color-bg-primary: #000000;
    84→  /* Page Background */
    85→  --color-bg-secondary: #0F0F0F;
    86→  /* Secondary sections */
    87→  --color-bg-card: #1A1A1A;
    88→  /* Standard Card */
    89→  --color-bg-card-hover: #22242B;
    90→  /* Card Hover */
    91→
    92→  /* ═══════════════════════════════════════════════════════════════════════
    93→     CANONICAL COLOR TOKENS — Surfaces & Borders
    94→     ═══════════════════════════════════════════════════════════════════════ */
    95→  --color-surface-1: #2F323A;
    96→  --color-surface-2: #5D5C5B;
    97→
    98→  --color-border-subtle: rgba(255, 255, 255, 0.05);
    99→  --color-border-default: rgba(255, 255, 255, 0.1);
   100→  --color-border-strong: rgba(255, 255, 255, 0.2);
   101→
   102→  /* ═══════════════════════════════════════════════════════════════════════
   103→     CANONICAL COLOR TOKENS — Text
   104→     ═══════════════════════════════════════════════════════════════════════ */
   105→  --color-text-primary: #FFFFFF;
   106→  /* Headings, Strong text */
   107→  --color-text-secondary: #D2D3D4;
   108→  /* Body text */
   109→  --color-text-muted: #5D5C5B;
   110→  /* Muted text */
   111→
   112→  /* ═══════════════════════════════════════════════════════════════════════
   113→     CANONICAL COLOR TOKENS — Brand
   114→     ═══════════════════════════════════════════════════════════════════════ */
   115→  --color-brand-primary: #F75105;
   116→  /* K3RN Orange */
   117→  --color-brand-secondary: #F78E21;
   118→  /* Lighter Orange */
   119→
   120→  /* ═══════════════════════════════════════════════════════════════════════
   121→     SHADOW TOKENS
   122→     ═══════════════════════════════════════════════════════════════════════ */
   123→  --shadow-sm: 0 1px 2px rgb(0 0 0 / 0.05);
   124→  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.3);
   125→  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.4);
   126→  --shadow-glow: 0 0 30px rgba(247, 81, 5, 0.3);
   127→
   128→  /* ═══════════════════════════════════════════════════════════════════════
   129→     SHADCN COMPATIBILITY LAYER
   130→     ═══════════════════════════════════════════════════════════════════════ */
   131→  --background: var(--color-bg-primary);
   132→  --foreground: var(--color-text-secondary);
   133→
   134→  --card: var(--color-bg-card);
   135→  --card-foreground: var(--color-text-secondary);
   136→
   137→  --popover: var(--color-bg-secondary);
   138→  --popover-foreground: var(--color-text-secondary);
   139→
   140→  --primary: var(--color-brand-primary);
   141→  --primary-foreground: #FFFFFF;
   142→
   143→  --secondary: var(--color-surface-1);
   144→  --secondary-foreground: var(--color-text-secondary);
   145→
   146→  --muted: var(--color-bg-secondary);
   147→  --muted-foreground: var(--color-text-muted);
   148→
   149→  --accent: var(--color-surface-1);
   150→  --accent-foreground: var(--color-text-primary);
   151→
   152→  --destructive: 0 84.2% 60.2%;
   153→  --destructive-foreground: 0 0% 98%;
   154→
   155→  --border: var(--color-border-default);
   156→  --input: var(--color-bg-secondary);
   157→  --ring: var(--color-brand-primary);
   158→
   159→  /* Chart colors */
   160→  --chart-1: var(--color-brand-primary);
   161→  --chart-2: var(--color-brand-secondary);
   162→  --chart-3: #5D5C5B;
   163→  --chart-4: #2F323A;
   164→  --chart-5: #000000;
   165→
   166→  /* Custom Utilities */
   167→  --shadow-glow: 0 0 30px rgba(247, 81, 5, 0.3);
   168→
   169→  /* Sidebar tokens */
   170→  --sidebar: var(--color-bg-secondary);
   171→  --sidebar-foreground: var(--color-text-secondary);
   172→  --sidebar-primary: var(--color-brand-primary);
   173→  --sidebar-primary-foreground: #FFFFFF;
   174→  --sidebar-accent: var(--color-surface-1);
   175→  --sidebar-accent-foreground: var(--color-text-primary);
   176→  --sidebar-border: var(--color-border-default);
   177→  --sidebar-ring: var(--color-brand-primary);
   178→}
   179→
   180→/* Dark mode class — ensures consistency */
   181→.dark {
   182→  --background: var(--color-bg-primary);
   183→  --foreground: var(--color-text-secondary);
   184→  --card: var(--color-bg-card);
   185→  --card-foreground: var(--color-text-secondary);
   186→  --popover: var(--color-bg-secondary);
   187→  --popover-foreground: var(--color-text-secondary);
   188→  --primary: var(--color-brand-primary);
   189→  --primary-foreground: #FFFFFF;
   190→  --secondary: var(--color-surface-1);
   191→  --secondary-foreground: var(--color-text-secondary);
   192→  --muted: var(--color-bg-secondary);
   193→  --muted-foreground: var(--color-text-muted);
   194→  --accent: var(--color-surface-1);
   195→  --accent-foreground: var(--color-text-primary);
   196→  --destructive: 0 84.2% 60.2%;
   197→  --destructive-foreground: 0 0% 98%;
   198→  --border: var(--color-border-default);
   199→  --input: var(--color-bg-secondary);
   200→  --ring: var(--color-brand-primary);
   201→}
   202→
   203→@layer base {
   204→  * {
   205→    @apply border-border outline-ring/50;
   206→  }
   207→
   208→  body {
   209→    @apply bg-background text-foreground antialiased selection:bg-[#F75105]/30 selection:text-white;
   210→    font-feature-settings: "rlig" 1, "calt" 1;
   211→  }
   212→}
   213→
   214→@layer utilities {
   215→  .shadow-glow {
   216→    box-shadow: var(--shadow-glow);
   217→  }
   218→}

