     1→<!DOCTYPE html>
     2→<html lang="fr" class="dark">
     3→<head>
     4→    <meta charset="UTF-8">
     5→    <meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→    <title>K3RN.LABS — Workspace Final Design</title>
     7→    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet">
     8→    <style>
     9→        /* ═══════════════════════════════════════════════════════════════
    10→           K3RN.LABS DESIGN TOKENS — Dark 900 Canvas System
    11→           ─────────────────────────────────────────────────────────────
    12→           Depth architecture (cool blue undertone):
    13→             L0  Canvas     #22242B  — page background
    14→             L-1 Recessed   #1A1C22  — inputs, insets, radar
    15→             L1  Card       #2C2F38  — elevated cards, dialogs
    16→             L2  Card Hover #363940  — interactive surfaces
    17→             L3  Surface    #464950  — buttons, controls, dock elements
    18→             L4  Surface Hi #62656D  — muted interactive, scrollbar
    19→           ═══════════════════════════════════════════════════════════════ */
    20→        :root {
    21→            /* ── Elevation layers ── */
    22→            --bg-primary: #22242B;
    23→            --bg-secondary: #1A1C22;
    24→            --bg-card: #2C2F38;
    25→            --bg-card-hover: #363940;
    26→            --surface-1: #464950;
    27→            --surface-2: #62656D;
    28→
    29→            /* ── Borders (calibrated for #22242B base) ── */
    30→            --border-subtle: rgba(255,255,255,0.06);
    31→            --border-default: rgba(255,255,255,0.10);
    32→            --border-strong: rgba(255,255,255,0.18);
    33→
    34→            /* ── Typography ── */
    35→            --text-primary: #F5F5F7;
    36→            --text-secondary: #A0A3AB;
    37→            --text-muted: #6C6F78;
    38→
    39→            /* ── Brand ── */
    40→            --brand-primary: #F75105;
    41→            --brand-secondary: #F78E21;
    42→
    43→            /* ── Shadows (warmer glow on darker canvas) ── */
    44→            --shadow-glow: 0 0 30px rgba(247,81,5,0.25);
    45→            --shadow-soft: 0 0 15px rgba(247,81,5,0.12);
    46→            --shadow-elevation: 0 8px 32px rgba(0,0,0,0.35);
    47→
    48→            /* ── Radii ── */
    49→            --radius-md: 8px;
    50→            --radius-lg: 12px;
    51→            --radius-xl: 16px;
    52→            --radius-2xl: 24px;
    53→            --radius-full: 9999px;
    54→
    55→            /* ── Spacing ── */
    56→            --space-1: 4px; --space-2: 8px; --space-3: 12px; --space-4: 16px;
    57→            --space-6: 24px; --space-8: 32px; --space-12: 48px; --space-16: 64px;
    58→
    59→            /* ── Decision palette ── */
    60→            --color-go: #22C55E; --color-explore: #F59E0B; --color-park: #6B7280; --color-kill: #EF4444;
    61→        }
    62→        * { margin: 0; padding: 0; box-sizing: border-box; }
    63→        body {
    64→            font-family: 'Inter', -apple-system, sans-serif;
    65→            background: var(--bg-primary);
    66→            color: var(--text-secondary);
    67→            -webkit-font-smoothing: antialiased;
    68→            overflow-x: hidden;
    69→            position: relative;
    70→        }
    71→        /* Canvas dot-grid pattern */
    72→        body::before {
    73→            content: '';
    74→            position: fixed; inset: 0; z-index: 0;
    75→            pointer-events: none;
    76→            background-image: radial-gradient(rgba(255,255,255,0.035) 1px, transparent 1px);
    77→            background-size: 24px 24px;
    78→        }
    79→        ::selection { background: rgba(247,81,5,0.3); color: white; }
    80→
    81→        /* ═══════ HEADER ═══════ */
    82→        .header {
    83→            position: sticky; top: 0; z-index: 50;
    84→            border-bottom: 1px solid var(--border-subtle);
    85→            background: rgba(34,36,43,0.88);
    86→            backdrop-filter: blur(24px) saturate(1.2);
    87→            -webkit-backdrop-filter: blur(24px) saturate(1.2);
    88→        }
    89→        .header-inner {
    90→            max-width: 1400px; margin: 0 auto;
    91→            display: flex; align-items: center; justify-content: space-between;
    92→            height: 64px; padding: 0 var(--space-8);
    93→        }
    94→        .header-left { display: flex; align-items: center; gap: var(--space-6); }
    95→        .logo {
    96→            width: 32px; height: 32px; background: var(--brand-primary);
    97→            border-radius: 8px; display: flex; align-items: center; justify-content: center;
    98→            font-weight: 800; font-size: 14px; color: white;
    99→            transition: transform 0.5s ease;
   100→        }
   101→        .logo:hover { transform: rotate(180deg); }
   102→        .divider { width: 1px; height: 20px; background: var(--border-default); }
   103→        .nav-links { display: flex; gap: var(--space-6); }
   104→        .nav-link {
   105→            font-size: 0.875rem; font-weight: 500; text-transform: uppercase;
   106→            letter-spacing: 0.1em; color: var(--text-secondary); text-decoration: none;
   107→            padding: 21px 0; position: relative; transition: color 0.2s;
   108→        }
   109→        .nav-link:hover { color: var(--text-primary); }
   110→        .nav-link.active { color: var(--brand-primary); }
   111→        .nav-link.active::after {
   112→            content: ''; position: absolute; bottom: 0; left: 0; right: 0;
   113→            height: 2px; background: var(--brand-primary);
   114→        }
   115→        .header-right { display: flex; align-items: center; gap: var(--space-3); }
   116→        .header-btn {
   117→            padding: 6px 12px; font-size: 0.75rem; color: var(--text-muted);
   118→            background: transparent; border: 1px solid var(--border-default);
   119→            border-radius: var(--radius-md); cursor: pointer; font-family: inherit;
   120→            transition: all 0.2s;
   121→        }
   122→        .header-btn:hover { color: var(--text-primary); border-color: var(--border-strong); background: var(--bg-card); }
   123→        .avatar {
   124→            width: 32px; height: 32px; border-radius: 50%;
   125→            background: var(--surface-1); border: 1px solid var(--border-default);
   126→            display: flex; align-items: center; justify-content: center;
   127→            font-size: 0.75rem; font-weight: 600; color: var(--text-secondary);
   128→        }
   129→
   130→        /* ═══════ MAIN ═══════ */
   131→        .main {
   132→            max-width: 1400px; margin: 0 auto;
   133→            padding: var(--space-12) var(--space-8) 160px;
   134→            position: relative; z-index: 1;
   135→        }
   136→
   137→        /* ═══════ WELCOME HERO ═══════ */
   138→        .welcome {
   139→            margin-bottom: var(--space-12);
   140→            background: var(--bg-secondary);
   141→            border: 1px solid var(--border-subtle);
   142→            border-radius: var(--radius-2xl);
   143→            padding: var(--space-8);
   144→            box-shadow: inset 0 1px 0 rgba(0,0,0,0.2), inset 0 -1px 0 rgba(255,255,255,0.02);
   145→        }
   146→        .welcome h1 {
   147→            font-size: 2.5rem; font-weight: 300; color: var(--text-primary);
   148→            letter-spacing: -0.02em; line-height: 1.1;
   149→            margin-bottom: var(--space-2);
   150→        }
   151→        .welcome h1 span { color: var(--text-muted); font-weight: 300; }
   152→        .welcome-sub {
   153→            font-size: 1rem; color: var(--text-muted); font-weight: 400;
   154→        }
   155→        .welcome-sub strong { color: var(--text-secondary); font-weight: 500; }
   156→
   157→        /* ═══════ GRID ═══════ */
   158→        .projects-grid {
   159→            display: grid;
   160→            grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
   161→            gap: var(--space-6);
   162→        }
   163→
   164→        /* ═══════ PLATINUM CARD ═══════ */
   165→        .p-card {
   166→            background:
   167→                linear-gradient(180deg, rgba(255,255,255,0.05) 0%, rgba(255,255,255,0.01) 100%),
   168→                var(--bg-card);
   169→            border-top: 1px solid rgba(255,255,255,0.10);
   170→            border-left: 1px solid rgba(255,255,255,0.05);
   171→            border-right: 1px solid rgba(255,255,255,0.05);
   172→            border-bottom: 1px solid rgba(0,0,0,0.25);
   173→            border-radius: var(--radius-2xl);
   174→            overflow: hidden;
   175→            cursor: pointer;
   176→            transition: all 0.3s ease;
   177→            position: relative;
   178→            box-shadow: 0 2px 8px rgba(0,0,0,0.15);
   179→        }
   180→        .p-card:hover {
   181→            background:
   182→                linear-gradient(180deg, rgba(255,255,255,0.08) 0%, rgba(255,255,255,0.025) 100%),
   183→                var(--bg-card-hover);
   184→            border-top-color: rgba(255,255,255,0.20);
   185→            transform: translateY(-3px);
   186→            box-shadow: 0 16px 48px rgba(0,0,0,0.35), 0 2px 8px rgba(0,0,0,0.2);
   187→        }
   188→
   189→        /* Color accent */
   190→        .p-card .accent { position: absolute; top: 0; left: 0; right: 0; height: 3px; }
   191→
   192→        /* Card inner */
   193→        .p-card-body { padding: var(--space-8); display: flex; flex-direction: column; min-height: 280px; }
   194→
   195→        /* Card header row */
   196→        .p-card-head { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: var(--space-4); }
   197→        .p-card-head .folder-icon {
   198→            width: 40px; height: 40px; border-radius: var(--radius-lg);
   199→            background: var(--bg-primary); border: 1px solid var(--border-subtle);
   200→            display: flex; align-items: center; justify-content: center;
   201→        }
   202→        .p-card-head .folder-icon svg { width: 18px; height: 18px; color: var(--text-muted); }
   203→        .p-card-score {
   204→            text-align: right;
   205→        }
   206→        .p-card-score .val {
   207→            font-size: 1.75rem; font-weight: 300; color: var(--text-primary);
   208→            font-variant-numeric: tabular-nums; line-height: 1;
   209→        }
   210→        .p-card-score .val.dim { color: var(--text-muted); }
   211→        .p-card-score .unit { font-size: 0.75rem; color: var(--text-muted); margin-left: 1px; }
   212→
   213→        /* Card body text */
   214→        .p-card-title {
   215→            font-size: 1.25rem; font-weight: 600; color: var(--text-primary);
   216→            line-height: 1.25; margin-bottom: var(--space-2);
   217→            display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden;
   218→        }
   219→        .p-card-desc {
   220→            font-size: 0.875rem; color: var(--text-muted); line-height: 1.5;
   221→            display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden;
   222→        }
   223→
   224→        /* Card footer */
   225→        .p-card-foot {
   226→            margin-top: auto; padding-top: var(--space-4);
   227→            border-top: 1px solid var(--border-subtle);
   228→            display: flex; justify-content: space-between; align-items: center;
   229→        }
   230→        .p-card-date {
   231→            font-size: 0.6875rem; font-weight: 500; color: var(--text-muted);
   232→            text-transform: uppercase; letter-spacing: 0.05em;
   233→            display: flex; align-items: center; gap: 6px;
   234→        }
   235→        .p-card-date svg { width: 12px; height: 12px; }
   236→        .p-card-foot-right { display: flex; align-items: center; gap: var(--space-2); }
   237→        .p-card-arrow {
   238→            opacity: 0; transition: all 0.3s;
   239→            color: var(--text-secondary);
   240→        }
   241→        .p-card:hover .p-card-arrow { opacity: 1; }
   242→        .p-card-arrow svg { width: 16px; height: 16px; }
   243→
   244→        /* Badge */
   245→        .badge {
   246→            display: inline-flex; align-items: center;
   247→            padding: 3px 10px; border-radius: var(--radius-full);
   248→            font-size: 0.625rem; font-weight: 700; text-transform: uppercase;
   249→            letter-spacing: 0.08em; border: 1px solid;
   250→        }
   251→        .badge-go { background: rgba(34,197,94,0.1); color: #4ade80; border-color: rgba(34,197,94,0.2); }
   252→        .badge-explore { background: rgba(245,158,11,0.1); color: #fbbf24; border-color: rgba(245,158,11,0.2); }
   253→        .badge-park { background: rgba(107,114,128,0.1); color: #9ca3af; border-color: rgba(107,114,128,0.2); }
   254→        .badge-kill { background: rgba(239,68,68,0.1); color: #f87171; border-color: rgba(239,68,68,0.2); }
   255→
   256→        /* ═══════ NEW PROJECT CARD ═══════ */
   257→        .new-card {
   258→            background: var(--bg-card);
   259→            border: 1px dashed var(--border-default);
   260→            border-radius: var(--radius-2xl);
   261→            min-height: 280px;
   262→            display: flex; flex-direction: column; align-items: center; justify-content: center;
   263→            gap: var(--space-4);
   264→            cursor: pointer;
   265→            transition: all 0.2s;
   266→        }
   267→        .new-card:hover {
   268→            border-color: var(--border-strong);
   269→            background: var(--bg-card-hover);
   270→        }
   271→        .new-card .plus-circle {
   272→            width: 48px; height: 48px; border-radius: 50%;
   273→            background: var(--bg-primary); border: 1px solid var(--border-default);
   274→            display: flex; align-items: center; justify-content: center;
   275→            transition: all 0.3s;
   276→        }
   277→        .new-card:hover .plus-circle {
   278→            border-color: var(--border-strong); background: var(--bg-card-hover);
   279→        }
   280→        .new-card .plus-circle svg { width: 20px; height: 20px; color: var(--text-muted); transition: color 0.2s; }
   281→        .new-card:hover .plus-circle svg { color: var(--text-primary); }
   282→        .new-card .new-label {
   283→            font-size: 0.6875rem; font-weight: 700; color: var(--text-muted);
   284→            text-transform: uppercase; letter-spacing: 0.1em;
   285→            transition: color 0.2s;
   286→        }
   287→        .new-card:hover .new-label { color: var(--text-secondary); }
   288→
   289→        /* ═══════ PROJECT DETAIL OVERLAY ═══════ */
   290→        .overlay-bg {
   291→            position: fixed; inset: 0; z-index: 100;
   292→            background: rgba(15,16,20,0.70);
   293→            backdrop-filter: blur(12px) saturate(0.8);
   294→            -webkit-backdrop-filter: blur(12px) saturate(0.8);
   295→            display: none; align-items: center; justify-content: center;
   296→            padding: var(--space-8);
   297→        }
   298→        .overlay-bg.visible { display: flex; }
   299→        .overlay-card {
   300→            background: var(--bg-card);
   301→            border-top: 1px solid rgba(255,255,255,0.10);
   302→            border-left: 1px solid rgba(255,255,255,0.06);
   303→            border-right: 1px solid rgba(255,255,255,0.06);
   304→            border-bottom: 1px solid rgba(0,0,0,0.3);
   305→            border-radius: var(--radius-2xl);
   306→            max-width: 960px; width: 100%;
   307→            max-height: 90vh; overflow-y: auto;
   308→            position: relative;
   309→            box-shadow: 0 40px 100px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.03);
   310→            scrollbar-width: thin; scrollbar-color: var(--surface-1) transparent;
   311→        }
   312→        .overlay-card::-webkit-scrollbar { width: 4px; }
   313→        .overlay-card::-webkit-scrollbar-thumb { background: var(--surface-1); border-radius: 999px; }
   314→        .overlay-close {
   315→            position: absolute; top: var(--space-6); right: var(--space-6);
   316→            width: 36px; height: 36px; border-radius: 50%;
   317→            background: var(--surface-1); border: none; color: var(--text-muted);
   318→            cursor: pointer; display: flex; align-items: center; justify-content: center;
   319→            transition: all 0.2s; z-index: 10;
   320→        }
   321→        .overlay-close:hover { color: var(--text-primary); background: var(--bg-primary); }
   322→        .overlay-close svg { width: 18px; height: 18px; }
   323→        .overlay-inner { padding: var(--space-8); padding-top: var(--space-8); }
   324→
   325→        /* Detail layout: 2-col */
   326→        .detail-grid {
   327→            display: grid;
   328→            grid-template-columns: 1fr 1fr;
   329→            gap: var(--space-8);
   330→        }
   331→
   332→        /* Radar */
   333→        .radar-wrap {
   334→            background: var(--bg-primary);
   335→            border: 1px solid var(--border-subtle);
   336→            border-radius: var(--radius-xl);
   337→            padding: var(--space-6);
   338→            display: flex; align-items: center; justify-content: center;
   339→            position: relative;
   340→            aspect-ratio: 1;
   341→            box-shadow: inset 0 2px 4px rgba(0,0,0,0.15);
   342→        }
   343→        .radar-wrap svg { width: 100%; max-width: 320px; }
   344→        .radar-badge { position: absolute; bottom: var(--space-4); left: var(--space-4); }
   345→
   346→        /* Detail right col */
   347→        .detail-right { display: flex; flex-direction: column; }
   348→        .detail-right h2 {
   349→            font-size: 1.5rem; font-weight: 600; color: var(--text-primary);
   350→            line-height: 1.2; margin-bottom: var(--space-2);
   351→        }
   352→        .detail-right .desc {
   353→            font-size: 0.9375rem; color: var(--text-secondary); font-weight: 300;
   354→            line-height: 1.7; margin-bottom: var(--space-6);
   355→        }
   356→        .detail-metrics {
   357→            display: grid; grid-template-columns: 1fr 1fr; gap: var(--space-3);
   358→            margin-bottom: var(--space-6);
   359→        }
   360→        .metric-block {
   361→            background: var(--bg-primary); border: 1px solid var(--border-subtle);
   362→            border-radius: var(--radius-xl); padding: var(--space-4);
   363→            box-shadow: inset 0 1px 2px rgba(0,0,0,0.1);
   364→        }
   365→        .metric-label {
   366→            font-size: 0.625rem; font-weight: 700; text-transform: uppercase;
   367→            letter-spacing: 0.1em; color: var(--text-muted); margin-bottom: var(--space-2);
   368→        }
   369→        .metric-val {
   370→            font-size: 2rem; font-weight: 300; color: var(--text-primary);
   371→            font-variant-numeric: tabular-nums; line-height: 1;
   372→        }
   373→        .metric-val .u { font-size: 0.875rem; color: var(--text-muted); }
   374→
   375→        .separator {
   376→            height: 1px; background: var(--border-subtle); margin: var(--space-6) 0;
   377→        }
   378→        .section-label {
   379→            font-size: 0.75rem; font-weight: 700; text-transform: uppercase;
   380→            letter-spacing: 0.1em; color: var(--brand-primary); margin-bottom: var(--space-4);
   381→        }
   382→
   383→        /* Axis bars */
   384→        .axis-row {
   385→            display: flex; align-items: center; gap: var(--space-3);
   386→            margin-bottom: var(--space-3);
   387→        }
   388→        .axis-lbl { width: 130px; font-size: 0.8125rem; font-weight: 500; color: var(--text-secondary); flex-shrink: 0; }
   389→        .axis-track { flex: 1; height: 5px; background: var(--surface-1); border-radius: 999px; overflow: hidden; }
   390→        .axis-fill { height: 100%; border-radius: 999px; transition: width 0.8s ease-out; }
   391→        .axis-val { font-size: 0.8125rem; font-weight: 500; color: var(--text-secondary); font-variant-numeric: tabular-nums; min-width: 36px; text-align: right; }
   392→
   393→        /* Synthesis */
   394→        .synthesis {
   395→            font-size: 0.9375rem; font-weight: 300; color: var(--text-secondary);
   396→            line-height: 1.8; font-style: italic;
   397→            border-left: 2px solid var(--border-default); padding-left: var(--space-6);
   398→            margin: var(--space-3) 0;
   399→        }
   400→
   401→        /* Risks */
   402→        .risk-list { list-style: none; }
   403→        .risk-item {
   404→            display: flex; align-items: flex-start; gap: var(--space-3);
   405→            padding: var(--space-2) 0; font-size: 0.875rem;
   406→            color: var(--text-secondary); line-height: 1.5;
   407→        }
   408→        .risk-dot {
   409→            width: 6px; height: 6px; border-radius: 50%;
   410→            background: var(--color-kill); margin-top: 7px;
   411→            flex-shrink: 0; opacity: 0.7;
   412→        }
   413→
   414→        /* Buttons */
   415→        .btn-row { display: flex; gap: var(--space-3); margin-top: var(--space-6); }
   416→        .btn-primary {
   417→            display: inline-flex; align-items: center; gap: var(--space-2);
   418→            padding: var(--space-3) var(--space-6);
   419→            background: var(--brand-primary); color: white; border: none;
   420→            border-radius: var(--radius-md); font-size: 0.875rem; font-weight: 600;
   421→            font-family: inherit; cursor: pointer; transition: all 0.2s;
   422→        }
   423→        .btn-primary:hover { background: var(--brand-secondary); box-shadow: var(--shadow-glow); transform: translateY(-1px); }
   424→        /* Lab arrow animation — ↙ idle → ↗ on hover */
   425→        .btn-lab-arrow {
   426→            display: inline-flex;
   427→            transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
   428→            transform: rotate(180deg);
   429→        }
   430→        .btn-primary:hover .btn-lab-arrow {
   431→            transform: rotate(0deg);
   432→        }
   433→        .btn-secondary {
   434→            display: inline-flex; align-items: center; gap: var(--space-2);
   435→            padding: var(--space-3) var(--space-6);
   436→            background: transparent; color: var(--text-primary);
   437→            border: 1px solid var(--border-default);
   438→            border-radius: var(--radius-md); font-size: 0.875rem; font-weight: 500;
   439→            font-family: inherit; cursor: pointer; transition: all 0.2s;
   440→        }
   441→        .btn-secondary:hover { background: var(--bg-card); border-color: var(--border-strong); }
   442→
   443→        /* Editable fields */
   444→        .edit-section { display: flex; flex-direction: column; gap: var(--space-4); }
   445→        .edit-field { display: flex; flex-direction: column; gap: var(--space-2); }
   446→        .edit-label {
   447→            font-size: 0.75rem; font-weight: 700; text-transform: uppercase;
   448→            letter-spacing: 0.1em; color: var(--brand-primary);
   449→        }
   450→        .edit-input {
   451→            background: var(--bg-primary); border: 1px solid var(--border-default);
   452→            border-radius: var(--radius-md); padding: var(--space-3) var(--space-4);
   453→            color: var(--text-primary); font-family: inherit; font-size: 0.9375rem;
   454→            font-weight: 500; outline: none; transition: all 0.2s;
   455→        }
   456→        .edit-input:focus { border-color: var(--brand-primary); box-shadow: 0 0 0 3px rgba(247,81,5,0.1); }
   457→        .edit-input::placeholder { color: var(--text-muted); font-weight: 400; }
   458→        .edit-textarea {
   459→            background: var(--bg-primary); border: 1px solid var(--border-default);
   460→            border-radius: var(--radius-md); padding: var(--space-3) var(--space-4);
   461→            color: var(--text-secondary); font-family: inherit; font-size: 0.875rem;
   462→            font-weight: 400; line-height: 1.6; outline: none; transition: all 0.2s;
   463→            resize: vertical; min-height: 80px;
   464→        }
   465→        .edit-textarea:focus { border-color: var(--brand-primary); box-shadow: 0 0 0 3px rgba(247,81,5,0.1); }
   466→        .edit-textarea::placeholder { color: var(--text-muted); }
   467→
   468→        /* Action buttons (archive, delete) */
   469→        .actions-row {
   470→            display: flex; align-items: center; gap: var(--space-3);
   471→            padding-top: var(--space-4);
   472→        }
   473→        .btn-ghost {
   474→            display: inline-flex; align-items: center; gap: var(--space-2);
   475→            padding: var(--space-2) var(--space-4);
   476→            background: transparent; color: var(--text-muted);
   477→            border: 1px solid transparent;
   478→            border-radius: var(--radius-md); font-size: 0.8125rem; font-weight: 500;
   479→            font-family: inherit; cursor: pointer; transition: all 0.2s;
   480→        }
   481→        .btn-ghost:hover { color: var(--text-secondary); background: var(--bg-primary); border-color: var(--border-subtle); }
   482→        .btn-ghost svg { width: 14px; height: 14px; }
   483→        .btn-ghost-danger:hover { color: var(--color-kill); background: rgba(239,68,68,0.06); border-color: rgba(239,68,68,0.15); }
   484→        .actions-spacer { flex: 1; }
   485→
   486→        /* ═══════ FLOATING DOCK ═══════ */
   487→        .dock {
   488→            position: fixed; bottom: 32px; left: 50%; transform: translateX(-50%); z-index: 60;
   489→            display: flex; align-items: center; gap: var(--space-2);
   490→            padding: 8px; border-radius: var(--radius-2xl);
   491→            background: linear-gradient(180deg, rgba(26,28,34,0.94) 0%, rgba(18,19,24,0.97) 100%);
   492→            backdrop-filter: blur(32px) saturate(1.5); -webkit-backdrop-filter: blur(32px) saturate(1.5);
   493→            border-top: 1px solid rgba(255,255,255,0.10);
   494→            border-left: 1px solid rgba(255,255,255,0.05);
   495→            border-right: 1px solid rgba(255,255,255,0.05);
   496→            border-bottom: 1px solid rgba(0,0,0,0.4);
   497→            box-shadow: 0 20px 60px rgba(0,0,0,0.45), 0 0 0 0.5px rgba(255,255,255,0.04), inset 0 1px 0 rgba(255,255,255,0.04);
   498→        }
   499→        .dock-group {
   500→            display: flex; padding: 3px;
   501→            background: rgba(0,0,0,0.25); border-radius: var(--radius-lg);
   502→            border: 1px solid rgba(255,255,255,0.05);
   503→        }
   504→        .dock-btn {
   505→            width: 36px; height: 36px; border-radius: var(--radius-lg);
   506→            display: flex; align-items: center; justify-content: center;
